import ast
import operator

class SafeMathEvaluator(ast.NodeVisitor):
    """Whitelist only safe mathematical operations."""

    OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.Mod: operator.mod,
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def visit_BinOp(self, node):
        left = self.visit(node.left)
        right = self.visit(node.right)
        op_type = type(node.op)

        if op_type in self.OPERATORS:
            return self.OPERATORS[op_type](left, right)
        raise ValueError(f"Operator {op_type} not allowed")

    def visit_UnaryOp(self, node):
        operand = self.visit(node.operand)
        op_type = type(node.op)

        if op_type in self.OPERATORS:
            return self.OPERATORS[op_type](operand)
        raise ValueError(f"Unary operator {op_type} not allowed")

    def visit_Constant(self, node):
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Only numeric constants are allowed")

    # Fallback for Python < 3.8
    def visit_Num(self, node):
        if isinstance(node.n, (int, float)):
            return node.n
        raise ValueError("Only numeric constants are allowed")

    def generic_visit(self, node):
        raise ValueError(f"Unauthorized node type: {type(node).__name__}")

def safe_math_eval(expression: str) -> float:
    """
    Parse and evaluate a math expression securely.
    Raises ValueError on unsafe input.
    """
    try:
        tree = ast.parse(expression, mode='eval')
        return SafeMathEvaluator().visit(tree.body)
    except Exception as e:
        raise ValueError(f"Security Violation or Syntax Error: {e}")

# Example Usage
if __name__ == "__main__":
    try:
        print(safe_math_eval("2 + 2 * 5"))      # Output: 12
        print(safe_math_eval("10 ** 2"))        # Output: 100
        # print(safe_math_eval("__import__('os')")) # Raises ValueError
    except ValueError as err:
        print(err)
```

### Security Mitigation Details:
1.  **AST Parsing:** Converts code into a tree structure without executing it.
2.  **Node Whitelisting:** The `generic_visit` method blocks any node type not explicitly defined (e.g., `ast.Call`, `ast.Attribute`, `ast.Name`). This prevents function calls like `__import__('os')`.
3.  **Operator Control:** Only standard arithmetic operators are mapped to the `operator` module.
4.  **Constant Validation:** Ensures only numbers are used, preventing string manipulation or injection.

